 19→
 20→/** @file*/
 21→
 22→#include "internal_nn_math.h"
 23→#include "riscv_nn_support.h"
 24→
 25→//// Convolution Functions
 26→
 27→int32_t riscv_nn_conv_HWC_s8_s8_s8_sft_bias_fast(const q7_t * in_tensor,
 28→                                const uint16_t in_tensor_dim,
 29→                                const uint16_t in_tensor_ch,
 30→                                const q7_t * ker_weight,
 31→                                const uint16_t out_tensor_ch,
 32→                                const uint16_t ker_dim,
 33→                                const uint16_t pad,
 34→                                const uint16_t stride,
 35→                                const q7_t * bias,
 36→                                const uint16_t bias_lshift,
 37→                                const uint16_t out_rshift,
 38→                                q7_t * out_tensor,
 39→                                const uint16_t out_tensor_dim,
 40→                                q15_t * in_tmp_buf,
 41→                                q7_t * tmp_buf)
 42→{
 43→#ifdef ENA_EMPTY_FUN
 44→    //empty body
 45→#else
 46→    if (in_tensor_ch % 4 != 0 || out_tensor_ch % 2 != 0)
 47→    {
 48→        /* check if the input dimension meets the constraints */
 49→        return -1;
 50→    }
 51→
 52→#if defined(ENA_VEC_ISA) || defined(ENA_DSP_ISA_V5)
 53→    int16_t   i_out_y, i_out_x, i_ker_y, i_ker_x;
 54→
 55→    /*
 56→     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
 57→     *  im2col are done to output in q15_t format from q7_t input
 58→     */
 59→
 60→    q7_t     *pBuffer = (q7_t*)in_tmp_buf;
 61→    q7_t     *pOut = out_tensor;
 62→#if defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 1000) && defined(ENA_NDS_V5_VEC_DOT_PROD)
 63→#define BATCH_PIXELS 4
 64→#define GEMM_KERNEL nn_mat_mul_kernel_q7_unroll4
 65→#else
 66→#define BATCH_PIXELS 2
 67→#define GEMM_KERNEL nn_mat_mul_kernel_q7
 68→#endif
 69→    int bound_begin = (pad + stride - 1) / stride;
 70→    int bound_end   = (in_tensor_dim + pad - ker_dim + stride) / stride;
 71→
 72→    /*
 73→     *  Here we split the entire matrix into three regions depending on the pad situation
 74→     *    Top: i_out_y from 0 to pad - 1
 75→     * Middle: i_out_y from pad to out_tensor_dim-pad-1
 76→     * Bottom: i_out_y from out_tensor_dim-pad to out_tensor_dim-1
 77→     */
 78→
 79→    /* top part */
 80→    for (i_out_y = 0; i_out_y < bound_begin; i_out_y++)
 81→    {
 82→        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
 83→        {
 84→            /* This part implements the im2col function */
 85→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
 86→            {
 87→                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
 88→                {
 89→                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim || i_ker_x < 0 || i_ker_x >= in_tensor_dim)
 90→                    {
 91→                        nn_set_zero_s8(pBuffer, sizeof(q7_t)*in_tensor_ch);
 92→                    }
 93→                    else
 94→                    {
 95→                        nn_dup_s8((q7_t *) in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
 96→                    }
 97→                    pBuffer += in_tensor_ch;
 98→                }
 99→            }
100→
101→            if (pBuffer == (q7_t*)in_tmp_buf + BATCH_PIXELS * in_tensor_ch * ker_dim * ker_dim)
102→            {
103→                pOut = GEMM_KERNEL(ker_weight,
104→                                   (q7_t*)in_tmp_buf,
105→                                   out_tensor_ch,
106→                                   in_tensor_ch * ker_dim * ker_dim,
107→                                   bias_lshift,
108→                                   out_rshift,
109→                                   bias,
110→                                   pOut);
111→                /* counter reset */
112→                pBuffer = (q7_t*)in_tmp_buf;
113→            }
114→        }
115→    }
116→
117→    /* middle part, here we also divide the x into left, mid and right */
118→    for (; i_out_y < bound_end; i_out_y++)
119→    {
120→        /* left part */
121→        for (i_out_x = 0; i_out_x < bound_begin; i_out_x++)
122→        {
123→            /* This part implements the im2col function */
124→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
125→            {
126→                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
127→                {
128→                    if (i_ker_x < 0 || i_ker_x >= in_tensor_dim)
129→                    {
130→                        nn_set_zero_s8(pBuffer, sizeof(q7_t)*in_tensor_ch);
131→                    }
132→                    else
133→                    {
134→                        nn_dup_s8
135→                        ((q7_t *) in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
136→                    }
137→                    pBuffer += in_tensor_ch;
138→                }
139→            }
140→
141→            if (pBuffer == (q7_t*)in_tmp_buf + BATCH_PIXELS * in_tensor_ch * ker_dim * ker_dim)
142→            {
143→                pOut = GEMM_KERNEL(ker_weight,
144→                                   (q7_t*)in_tmp_buf,
145→                                   out_tensor_ch,
146→                                   in_tensor_ch * ker_dim * ker_dim,
147→                                   bias_lshift,
148→                                   out_rshift,
149→                                   bias,
150→                                   pOut);
151→                /* counter reset */
152→                pBuffer = (q7_t*)in_tmp_buf;
153→            }
154→        }
155→
156→        /* mid part */
157→        for (; i_out_x < bound_end; i_out_x++)
158→        {
159→            /* This part implements the im2col function */
160→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
161→            {
162→                nn_dup_s8((q7_t *) in_tensor + (i_ker_y * in_tensor_dim + i_out_x * stride - pad) * in_tensor_ch, pBuffer, in_tensor_ch * ker_dim);
163→                pBuffer += in_tensor_ch * ker_dim;
164→            }
165→
166→            if (pBuffer == (q7_t*)in_tmp_buf + BATCH_PIXELS * in_tensor_ch * ker_dim * ker_dim)
167→            {
168→                pOut = GEMM_KERNEL(ker_weight,
169→                                   (q7_t*)in_tmp_buf,
170→                                   out_tensor_ch,
171→                                   in_tensor_ch * ker_dim * ker_dim,
172→                                   bias_lshift,
173→                                   out_rshift,
174→                                   bias,
175→                                   pOut);
176→                /* counter reset */
177→                pBuffer = (q7_t*)in_tmp_buf;
178→            }
179→        }
180→
181→        /* right part */
182→        for (; i_out_x < out_tensor_dim; i_out_x++)
183→        {
184→            /* This part implements the im2col function */
185→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
186→            {
187→                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
188→                {
189→                    if (i_ker_x < 0 || i_ker_x >= in_tensor_dim)
190→                    {
191→                        nn_set_zero_s8(pBuffer, sizeof(q7_t)*in_tensor_ch);
192→                    }
193→                    else
194→                    {
195→                        nn_dup_s8((q7_t *) in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
196→                    }
197→                    pBuffer += in_tensor_ch;
198→                }
199→            }
200→
201→            if (pBuffer == (q7_t*)in_tmp_buf + BATCH_PIXELS * in_tensor_ch * ker_dim * ker_dim)
202→            {
203→                pOut = GEMM_KERNEL(ker_weight,
204→                                   (q7_t*)in_tmp_buf,
205→                                   out_tensor_ch,
206→                                   in_tensor_ch * ker_dim * ker_dim,
207→                                   bias_lshift,
208→                                   out_rshift,
209→                                   bias,
210→                                   pOut);
211→                /* counter reset */
212→                pBuffer = (q7_t*)in_tmp_buf;
213→            }
214→        }
215→    }
216→
217→    for (; i_out_y < out_tensor_dim; i_out_y++)
218→    {
219→        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
220→        {
221→            /* This part implements the im2col function */
222→            for (i_ker_y = i_out_y * stride - pad; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
223→            {
224→                for (i_ker_x = i_out_x * stride - pad; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
225→                {
226→                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim || i_ker_x < 0 || i_ker_x >= in_tensor_dim)
227→                    {
228→                        nn_set_zero_s8(pBuffer, sizeof(q7_t)*in_tensor_ch);
229→                    }
230→                    else
231→                    {
232→                        nn_dup_s8((q7_t *) in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
233→                    }
234→                    pBuffer += in_tensor_ch;
235→                }
236→            }
237→
238→            if (pBuffer == (q7_t*)in_tmp_buf + BATCH_PIXELS * in_tensor_ch * ker_dim * ker_dim)
239→            {
240→                pOut = GEMM_KERNEL(ker_weight,
241→                                   (q7_t*)in_tmp_buf,
242→                                   out_tensor_ch,
243→                                   in_tensor_ch * ker_dim * ker_dim,
244→                                   bias_lshift,
245→                                   out_rshift,
246→                                   bias,
247→                                   pOut);
248→                /* counter reset */
249→                pBuffer = (q7_t*)in_tmp_buf;
250→            }
251→        }
252→    }
253→
254→#undef BATCH_PIXELS
255→#undef GEMM_KERNEL
256→
257→    /* check if there is left-over for compute */
258→#if defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD) && defined(ENA_VEC_INTRINSIC)
259→    if (pBuffer != (q7_t *)in_tmp_buf)
260→    {
261→        unsigned vl;
262→        const q7_t *p_wt = ker_weight;
263→        int       i;
264→        uint16_t  colCnt = in_tensor_ch * ker_dim * ker_dim;
265→
266→        vl = __riscv_vsetvl_e32m1(1);
267→        vint32m1_t vZero = __riscv_vand(__riscv_vundefined_i32m1(), 0x0, vl);     //const zero for redsum
268→
269→        for (i = 0; i < out_tensor_ch; i++)
270→        {
271→            q7_t      *p_in = (q7_t*)in_tmp_buf;
272→            uint16_t colCnt2 = colCnt;
273→
274→            //clear v0~v7
275→            vl = __riscv_vsetvl_e32m8(colCnt);
276→            vint32m8_t vAccumulator = __riscv_vand(__riscv_vundefined_i32m8(), 0x0, vl);
277→
278→            while (colCnt2 > 0)
279→            {
280→                vl = __riscv_vsetvl_e8m8(colCnt2);
281→                //load src1
282→                vint8m8_t vP_wt_i8m8 = __riscv_vle8_v_i8m8(p_wt, vl);
283→                //load src2
284→                vint8m8_t vP_in_i8m8 = __riscv_vle8_v_i8m8(p_in, vl);
285→                //bump pointers and update loop counter
286→                colCnt2 -= vl;
287→                p_wt += vl;
288→                p_in += vl;
289→                //set the proper avl/SEW/LMUL values for vd4dot
290→                vl >>= 2;
291→                vl = __riscv_vsetvl_e32m8(vl);
292→                //acc += src1 * src2
293→                vAccumulator = __riscv_vd4dots_vv_i32m8(vAccumulator, vP_wt_i8m8, vP_in_i8m8, vl);
294→            }
295→
296→            vl = __riscv_vsetvl_e32m8(colCnt);  //note the avl here
297→            vint32m1_t vSum = __riscv_vredsum(vAccumulator, vZero, vl);
298→
299→            //add bias back
300→            vl = __riscv_vsetvl_e32m1(1);
301→            vint8mf4_t vBias_i8mf4 = __riscv_vle8_v_i8mf4(bias, vl);
302→            vint32m1_t vBias_i32m1 = __riscv_vsext_vf4(vBias_i8mf4, vl);
303→            vBias_i32m1 = __riscv_vsll(vBias_i32m1, bias_lshift, vl);
304→            vBias_i32m1 = __riscv_vadd(vBias_i32m1, NN_ROUND(out_rshift), vl);
305→            vSum = __riscv_vadd(vSum, vBias_i32m1, vl);
306→
307→            //scale down, clip and store the results
308→            vl = __riscv_vsetvl_e16mf2(1);
309→            vint16mf2_t vSum_i16mf2 = __riscv_vnsra(vSum, out_rshift, vl);
310→            vl = __riscv_vsetvl_e8mf4(1);
311→            vint8mf4_t vSum_i8mf4 = __riscv_vnclip(vSum_i16mf2, 0, __RISCV_VXRM_RNU, vl);
312→            __riscv_vse8(pOut, vSum_i8mf4, vl);
313→
314→            bias += vl;
315→            pOut += vl;
316→        }
317→    }
318→#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD)
319→    if (pBuffer != (q7_t *)in_tmp_buf)
320→    {
321→        unsigned vl;
322→        int       i;
323→        uint16_t  colCnt = in_tensor_ch * ker_dim * ker_dim;
324→        int       n_left = (int)(pBuffer - (q7_t *)in_tmp_buf) / colCnt;
325→        const q7_t *bias_base = bias;
326→
327→        NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
328→        NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0x0);     //const zero for redsum
329→
330→        for (int p = 0; p < n_left; p++)
331→        {
332→            const q7_t *p_wt = ker_weight;
333→            bias = bias_base;
334→
335→            for (i = 0; i < out_tensor_ch; i++)
336→            {
337→                q7_t      *p_in = (q7_t*)in_tmp_buf + (size_t)p * colCnt;
338→                uint16_t colCnt2 = colCnt;
339→
340→                //clear v0~v7
341→                NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
342→                NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x0);
343→
344→                while (colCnt2 > 0)
345→                {
346→                    NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
347→                    //load src1
348→                    NDS_VEC_VLB_V(NDS_VEC_V8, p_wt);
349→                    //load src2
350→                    NDS_VEC_VLB_V(NDS_VEC_V16, p_in);
351→                    //bump pointers and update loop counter
352→                    colCnt2 -= vl;
353→                    p_wt += vl;
354→                    p_in += vl;
355→                    //set the proper avl/SEW/LMUL values for vd4dot
356→                    vl >>= 2;
357→                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
358→                    //acc += src1 * src2
359→                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
360→                }
361→
362→                NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);  //note the avl here
363→                NDS_VEC_VREDSUM_VS(NDS_VEC_V8, NDS_VEC_V0, NDS_VEC_V31);
364→
365→                //add bias back
366→                NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
367→                NDS_VEC_VLB_V(NDS_VEC_V10, bias);
368→                NDS_VEC_VSEXT_VF4(NDS_VEC_V9, NDS_VEC_V10);
369→                NDS_VEC_VSLL_VX(NDS_VEC_V9, NDS_VEC_V9, bias_lshift);
370→                NDS_VEC_VADD_VX(NDS_VEC_V9, NDS_VEC_V9, NN_ROUND(out_rshift));
371→                NDS_VEC_VADD_VV(NDS_VEC_V8, NDS_VEC_V8, NDS_VEC_V9);
372→
373→                //scale down, clip and store the results
374→                NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M1);
375→                NDS_VEC_VNSRA_WX(NDS_VEC_V8, NDS_VEC_V8, out_rshift);
376→                NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
377→                NDS_VEC_VNCLIP_WI(NDS_VEC_V8, NDS_VEC_V8, 0);
378→                NDS_VEC_VSB_V(NDS_VEC_V8, pOut);
379→
380→                bias += vl;
381→                pOut += vl;
382→            }
383→        }
384→    }
385→#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_INTRINSIC)
386→    if (pBuffer != (q7_t *)in_tmp_buf)
387→    {
388→        unsigned vl;
389→        const q7_t *pA = ker_weight;
390→        int       i;
391→        uint16_t  colCnt = in_tensor_ch * ker_dim * ker_dim;
392→
393→        //set SEW for 1st time VMV_S_X
394→        //LMUL=8 is just for clear v8~v15 (vmv ignores LMUL)
395→        vl = __riscv_vsetvl_e32m8(colCnt);
396→
397→        for (i = 0; i < out_tensor_ch; i++)
398→        {
399→            q31_t     sum = ((q31_t)bias[i] << bias_lshift) + NN_ROUND(out_rshift);
400→            q7_t      *pB = (q7_t*)in_tmp_buf;
401→            uint16_t colCnt2 = colCnt;
402→
403→            //init
404→            vint32m1_t vBias = __riscv_vmv_s_x_i32m1(sum, vl);
405→            //clear v8~v15
406→            vint32m8_t vAcc = __riscv_vundefined_i32m8();
407→            vAcc = __riscv_vand_tu(vAcc, vAcc, 0, vl);
408→
409→            while(colCnt2 > 0)
410→            {
411→                vl = __riscv_vsetvl_e8m2(colCnt2);
412→                vint8m2_t vPa_i8 = __riscv_vundefined_i8m2();
413→                vint8m2_t vPb_i8 = __riscv_vundefined_i8m2();
414→                //load src1
415→                vPa_i8 = __riscv_vle8_tu(vPa_i8, pA, vl);
416→                //load src2
417→                vPb_i8 = __riscv_vle8_tu(vPb_i8, pB, vl);
418→                //acc += src1 * src2
419→                vAcc = __riscv_vqmacc_vv_i32m8_tu(vAcc, vPa_i8, vPb_i8, vl);
420→                //bump pointers and update loop counter
421→                colCnt2 -= vl;
422→                pA += vl;
423→                pB += vl;
424→            }
425→
426→            vl = __riscv_vsetvl_e32m8(colCnt);    //note the avl here
427→            vint32m1_t vAcc_sum = __riscv_vredsum(vAcc, vBias, vl);
428→            //move vr results to gpr
429→            sum = __riscv_vmv_x(vAcc_sum);
430→
431→            *pOut++ = NDS_ISA_SATS((sum >> out_rshift), 8);
432→        }
433→    }
434→#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100)
435→    if (pBuffer != (q7_t *)in_tmp_buf)
436→    {
437→        unsigned vl;
438→        const q7_t *pA = ker_weight;
439→        int       i;
440→        uint16_t  colCnt = in_tensor_ch * ker_dim * ker_dim;
441→
442→        //set SEW for 1st time VMV_S_X
443→        //LMUL=8 is just for clear v8~v15 (vmv ignores LMUL)
444→        NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
445→
446→        for (i = 0; i < out_tensor_ch; i++)
447→        {
448→            q31_t     sum = ((q31_t)bias[i] << bias_lshift) + NN_ROUND(out_rshift);
449→            q7_t      *pB = (q7_t*)in_tmp_buf;
450→            uint16_t colCnt2 = colCnt;
451→
452→            //init
453→            NDS_VEC_VMV_S_X(NDS_VEC_V0, sum);
454→            //clear v8~v15
455→            NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0x0);
456→
457→            while(colCnt2 > 0)
458→            {
459→                NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
